import React, { useMemo, useState } from 'react';
import './App.css';

type Product = {
  id: string;
  name: string;
  price: number;
  stock: number;
};

type CartItem = Product & {
  quantity: number;
};

const PRODUCTS: Product[] = [
  { id: 'p1', name: 'Wireless Headphones', price: 129.99, stock: 2 },
  { id: 'p2', name: 'Mechanical Keyboard', price: 89.5, stock: 3 },
  { id: 'p3', name: 'Ergonomic Mouse', price: 49.99, stock: 5 },
  { id: 'p4', name: 'USB-C Hub', price: 39, stock: 1 }
];

const currencyFormatter = new Intl.NumberFormat('en-US', {
  style: 'currency',
  currency: 'USD',
  minimumFractionDigits: 2,
  maximumFractionDigits: 2
});

function formatCurrency(value: number): string {
  return currencyFormatter.format(value);
}

export default function App() {
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [cartStatus, setCartStatus] = useState('');
  const [promoCode, setPromoCode] = useState('');
  const [promoApplied, setPromoApplied] = useState(false);
  const [promoFeedback, setPromoFeedback] = useState('');
  const [checkoutStatus, setCheckoutStatus] = useState('');

  const { totalQty, subtotal } = useMemo(() => ({
    totalQty: cartItems.reduce((sum, item) => sum + item.quantity, 0),
    subtotal: cartItems.reduce(
      (sum, item) => sum + item.price * item.quantity,
      0
    )
  }), [cartItems]);
  const discount = promoApplied ? subtotal * 0.1 : 0;
  const grandTotal = subtotal - discount;

  function quantityFor(productId: string): number {
    return cartItems.find(item => item.id === productId)?.quantity ?? 0;
  }

  function addToCart(product: Product) {
    const currentQuantity = quantityFor(product.id);
    if (currentQuantity >= product.stock) {
      setCartStatus(product.name + ' reached its stock limit.');
      return;
    }

    const nextQuantity = currentQuantity + 1;
    setCartItems(current => {
      const existing = current.find(item => item.id === product.id);
      if (!existing) {
        return [...current, { ...product, quantity: 1 }];
      }
      return current.map(item =>
        item.id === product.id
          ? { ...item, quantity: Math.min(item.quantity + 1, item.stock) }
          : item
      );
    });
    setCartStatus(
      nextQuantity === product.stock
        ? product.name + ' reached its stock limit.'
        : ''
    );
    setCheckoutStatus('');
  }

  function increaseQty(item: CartItem) {
    const currentQuantity = quantityFor(item.id);
    if (currentQuantity >= item.stock) {
      setCartStatus(item.name + ' reached its stock limit.');
      return;
    }

    const nextQuantity = currentQuantity + 1;
    setCartItems(current =>
      current.map(currentItem =>
        currentItem.id === item.id
          ? {
              ...currentItem,
              quantity: Math.min(currentItem.quantity + 1, currentItem.stock)
            }
          : currentItem
      )
    );
    setCartStatus(
      nextQuantity === item.stock
        ? item.name + ' reached its stock limit.'
        : ''
    );
    setCheckoutStatus('');
  }

  function decreaseQty(item: CartItem) {
    setCartItems(current => {
      const selected = current.find(currentItem => currentItem.id === item.id);
      if (!selected) return current;
      if (selected.quantity <= 1) {
        return current.filter(currentItem => currentItem.id !== item.id);
      }
      return current.map(currentItem =>
        currentItem.id === item.id
          ? { ...currentItem, quantity: currentItem.quantity - 1 }
          : currentItem
      );
    });
    setCartStatus('');
    setCheckoutStatus('');
  }

  function removeItem(item: CartItem) {
    setCartItems(current =>
      current.filter(currentItem => currentItem.id !== item.id)
    );
    setCartStatus('');
    setCheckoutStatus('');
  }

  function applyPromo(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    const normalizedCode = promoCode.trim().toUpperCase();
    setPromoCode(normalizedCode);

    if (normalizedCode === 'SAVE10') {
      setPromoApplied(true);
      setPromoFeedback('10% discount applied.');
      return;
    }

    setPromoApplied(false);
    setPromoFeedback('Promo code is invalid.');
  }

  function checkout() {
    if (!cartItems.length) return;
    setCartItems([]);
    setCartStatus('');
    setPromoCode('');
    setPromoApplied(false);
    setPromoFeedback('');
    setCheckoutStatus('Order placed.');
  }

  return (
    <main className="app">
      <section className="layout">
        <section className="column products-column">
          <h1 className="title">Products</h1>
          <ul className="product-list">
            {PRODUCTS.map(product => {
              const atStockLimit = quantityFor(product.id) >= product.stock;
              return (
                <li
                  className="product-card"
                  data-product-id={product.id}
                  key={product.id}
                >
                  <div className="product-main">
                    <div className="product-name">{product.name}</div>
                    <div className="product-price">
                      {formatCurrency(product.price)}
                    </div>
                    <div className="stock-count">{product.stock} in stock</div>
                  </div>
                  <button
                    type="button"
                    className="add-to-cart"
                    onClick={() => addToCart(product)}
                    disabled={atStockLimit}
                    aria-label={'Add ' + product.name + ' to cart'}
                  >
                    Add to cart
                  </button>
                </li>
              );
            })}
          </ul>
        </section>

        <section className="column cart-column">
          <header className="cart-header">
            <h1 className="title">Cart</h1>
            <p className="subtitle">
              Total items: <strong className="total-qty">{totalQty}</strong>
              {' · '}
              Total: <strong className="grand-total">{formatCurrency(grandTotal)}</strong>
            </p>
          </header>

          {cartItems.length > 0 ? (
            <ul className="cart-list">
              {cartItems.map(item => (
                <li
                  className="cart-row"
                  data-product-id={item.id}
                  key={item.id}
                >
                  <div className="cart-info">
                    <div className="cart-name">{item.name}</div>
                    <div className="cart-meta">
                      <span className="unit-price">
                        {formatCurrency(item.price)}
                      </span>
                      <span className="times">x</span>
                      <span className="qty">{item.quantity}</span>
                      <span className="equals">=</span>
                      <span className="line-total">
                        {formatCurrency(item.price * item.quantity)}
                      </span>
                    </div>
                  </div>

                  <div className="cart-actions">
                    <button
                      type="button"
                      className="ghost quantity-decrease"
                      onClick={() => decreaseQty(item)}
                      aria-label={'Decrease ' + item.name + ' quantity'}
                    >
                      −
                    </button>
                    <button
                      type="button"
                      className="ghost quantity-increase"
                      onClick={() => increaseQty(item)}
                      disabled={item.quantity >= item.stock}
                      aria-label={'Increase ' + item.name + ' quantity'}
                    >
                      +
                    </button>
                    <button
                      type="button"
                      className="danger remove-item"
                      onClick={() => removeItem(item)}
                      aria-label={'Remove ' + item.name + ' from cart'}
                    >
                      Remove
                    </button>
                  </div>
                </li>
              ))}
            </ul>
          ) : (
            <p className="empty">
              Your cart is empty. Add something from above.
            </p>
          )}

          <p
            id="cart-status"
            className="cart-status"
            role="status"
            aria-live="polite"
            aria-atomic="true"
          >
            {cartStatus}
          </p>

          <form className="promo-form" onSubmit={applyPromo}>
            <label htmlFor="promo-code">Promo code</label>
            <div className="promo-controls">
              <input
                id="promo-code"
                className="promo-input"
                value={promoCode}
                onChange={event => setPromoCode(event.target.value)}
                aria-describedby="promo-feedback"
                autoComplete="off"
              />
              <button type="submit" className="apply-promo">
                Apply
              </button>
            </div>
          </form>
          <p
            id="promo-feedback"
            className="promo-feedback"
            role="status"
            aria-live="polite"
            aria-atomic="true"
          >
            {promoFeedback}
          </p>

          <dl className="summary">
            <div>
              <dt>Subtotal</dt>
              <dd className="subtotal">{formatCurrency(subtotal)}</dd>
            </div>
            <div>
              <dt>Discount</dt>
              <dd className="discount">
                {promoApplied ? '-' : ''}{formatCurrency(discount)}
              </dd>
            </div>
            <div>
              <dt>Total</dt>
              <dd className="grand-total">{formatCurrency(grandTotal)}</dd>
            </div>
          </dl>

          <button
            type="button"
            className="checkout-button"
            onClick={checkout}
            disabled={!cartItems.length}
          >
            Checkout
          </button>
          <p
            className="checkout-status"
            role="status"
            aria-live="polite"
            aria-atomic="true"
          >
            {checkoutStatus}
          </p>
        </section>
      </section>
    </main>
  );
}
